DriveAudio:
    ; If the game is paused, then silence all channels
    ; by first disabling them, then enabling them.
    ;
    ; Then go drive tune channel 0 only.
    ;
    move.b  ($00E0,A4),D0
    beq  _L_z00_DriveAudio_Play
    moveq   #0,D0
    bsr     _apu_write_4015  ; APU/IO write
    moveq   #15,D0
    bsr     _apu_write_4015  ; APU/IO write
    bne  _L_z00_DriveAudio_Paused
    even
_L_z00_DriveAudio_Play:
    ; Else the game is not paused.
    ;
    ; Synchronize the APU frame counter once a video frame.
    ;
    move.b  #$FF,D0
    bsr     _apu_write_4017  ; APU/IO write
    ; Drive each game sound channel.
    ;
    bsr     DriveTune1
    bsr     DriveEffect
    bsr     DriveSample
    bsr     DriveSong
    even
_L_z00_DriveAudio_Paused:
    bsr     DriveTune0
    ; Reset all requests for sound.
    ;
    moveq   #0,D0
    move.b  D0,($0604,A4)
    move.b  D0,($0603,A4)
    move.b  D0,($0602,A4)
    move.b  D0,($0601,A4)
    move.b  D0,($0600,A4)
    rts

    even
TuneScripts0:
    dc.b    $1C, $4C, $27, $5C, $46, $67, $07, $95
    dc.b    $50, $08, $08, $08, $08, $08, $90, $08
    dc.b    $08, $08, $08, $08, $08, $08, $08, $08
    dc.b    $08, $08, $08, $00, $82, $4A, $48, $4A
    dc.b    $08, $08, $08, $08, $08, $08, $00, $9F
    dc.b    $1E, $22, $24, $26, $9F, $28, $2A, $2C
    dc.b    $2E, $9A, $28, $2A, $2C, $2E, $9C, $28
    dc.b    $2A, $2C, $2E, $96, $28, $2A, $2C, $2E
    dc.b    $98, $28, $2A, $2C, $2E, $00, $99, $42
    dc.b    $4A, $50, $54, $00, $99, $70, $0A, $70
    dc.b    $0E, $70, $10, $9F, $70, $2A, $12, $1E
    dc.b    $2A, $70, $1E, $00, $9A, $42, $08, $08
    dc.b    $56, $08, $08, $00, $08, $08, $00, $9F
    dc.b    $40, $30, $40, $3A, $28, $00

    even
L18C9_SilenceSong:
    jmp     SilenceSong

    even
DriveTune0:
    move.b  ($0604,A4),D0
    ; Tune $80 is only a signal to silence the song.
    ;
    bmi  L18C9_SilenceSong
    beq  _L_z00_DriveTune0_CheckCurrentTune
    ; If the requested tune is not "heart warning", then go play it.
    ;
    cmpi.b  #$40,D0
    bne  _L_z00_DriveTune0_ChangeTune
    ; Else only play "heart warning" if nothing else is playing.
    ;
    move.b  ($0605,A4),D2
    beq  _L_z00_DriveTune0_ChangeTune
    even
_L_z00_DriveTune0_CheckCurrentTune:
    move.b  ($0605,A4),D0
    bne  _L_z00_DriveTune0_KeepPlaying
    rts

    even
_L_z00_DriveTune0_ChangeTune:
    move.b  D0,($0605,A4)
    moveq   #0,D3
_anon_z00_0:
    ; Get the index for the song bit: 1 to 8.
    ;
    addq.b  #1,D3
    lsr.b  #1,D0   ; LSR A
    bcc  _anon_z00_0
    lea     (TuneScripts0-1).l,A0
    move.b  (A0,D3.W),D0
    move.b  D0,($060E,A4)
    even
_L_z00_DriveTune0_KeepPlaying:
    move.b  ($060E,A4),D3
    addq.b  #1,($060E,A4)
    lea     (TuneScripts0).l,A0
    move.b  (A0,D3.W),D0
    bmi  _L_z00_DriveTune0_PrepNote
    bne  _L_z00_DriveTune0_PlayNote
    ; We've reached the end of the tune.
    ;
    move.b  #$90,D2
    move.l  D0,-(SP)       ; save A (6502 STX/STY never modifies A)
    move.b  D2,D0  ; D2 → D0 for I/O write
    bsr     _apu_write_4000  ; APU/IO write
    move.l  (SP)+,D0       ; restore A
    moveq   #24,D2
    move.l  D0,-(SP)       ; save A (6502 STX/STY never modifies A)
    move.b  D2,D0  ; D2 → D0 for I/O write
    bsr     _apu_write_4003  ; APU/IO write
    move.l  (SP)+,D0       ; restore A
    moveq   #0,D2
    move.l  D0,-(SP)       ; save A (6502 STX/STY never modifies A)
    move.b  D2,D0  ; D2 → D0 for I/O write
    bsr     _apu_write_4002  ; APU/IO write
    move.l  (SP)+,D0       ; restore A
    move.b  D2,($0605,A4)
    rts

    even
_L_z00_DriveTune0_PrepNote:
    bsr     _apu_write_4000  ; APU/IO write
    move.b  ($060E,A4),D3
    addq.b  #1,($060E,A4)
    lea     (TuneScripts0).l,A0
    move.b  (A0,D3.W),D0
    even
_L_z00_DriveTune0_PlayNote:
    bsr     EmitSquareNote0
    moveq   #127,D0
    bsr     _apu_write_4001  ; APU/IO write
    rts

