    move.b  ($0604,A4),D0
    andi.b #$EF,D0
    bne  ContinueArrowSfx
    move.b  D0,($0604,A4)
    even
ContinueArrowSfx:
    move.b  ($0069,A4),D3
    lea     (ArrowSfxNotes-1).l,A0
