    even
PlayStairsSfx:
    move.b  D3,($0606,A4)
    moveq   #56,D0
    move.b  D0,($0069,A4)
_anon_z00_1:
    moveq   #13,D0
    move.b  D0,($0068,A4)
    even
ContinueStairsSfx:
    subq.b  #1,($0068,A4)
    move.b  ($0068,A4),D3
    beq  _anon_z00_1
    cmpi.b  #$07,D3
    bcs  _anon_z00_2
    moveq   #16,D0
    bne  SetSfxVolumeLength
_anon_z00_2:
    lea     (StairsSfxNotes-1).l,A0
    move.b  (A0,D3.W),D0
    even
PlaySfxNote:
    move.b  D0,D2
    andi.b #$0F,D0
    bsr     _apu_write_400e  ; APU/IO write
    move.b  D2,D0
    lsr.b  #1,D0   ; LSR A
    lsr.b  #1,D0   ; LSR A
    lsr.b  #1,D0   ; LSR A
    lsr.b  #1,D0   ; LSR A
    ori.b #$10,D0
    even
SetSfxVolumeLength:
    bsr     _apu_write_400c  ; APU/IO write
    moveq   #8,D0
    bsr     _apu_write_400f  ; APU/IO write
