DriveEffect:
    move.b  ($0603,A4),D3
    ; $80 is a signal to silence samples and tune 1.
    ;
    bmi  SilenceSample
    move.b  ($0606,A4),D0
    move.b  ($0603,A4),D1
    lsr.b  #1,D1   ; LSR EffectRequest
    move.b  D1,($0603,A4)
    bcs  PlaySwordSfx
    lsr.b  #1,D0   ; LSR A
    bcs  ContinueSwordSfx
    move.b  ($0603,A4),D1
    lsr.b  #1,D1   ; LSR EffectRequest
    move.b  D1,($0603,A4)
    bcs  PlayArrowSfx
    lsr.b  #1,D0   ; LSR A
    bcs  ContinueArrowSfx
