    move.b  D1,($0603,A4)
    bcs  _L_z00_DriveEffect_PlayFlameSfx
    lsr.b  #1,D0   ; LSR A
    bcs  _L_z00_DriveEffect_ContinueFlameSfx
    move.b  ($0603,A4),D1
    lsr.b  #1,D1   ; LSR EffectRequest
    move.b  D1,($0603,A4)
    bcs  PlayStairsSfx
    lsr.b  #1,D0   ; LSR A
    bcs  ContinueStairsSfx
    move.b  ($0603,A4),D1
    lsr.b  #1,D1   ; LSR EffectRequest
    move.b  D1,($0603,A4)
    bcs  _L_z00_DriveEffect_PlayBombSfx
    lsr.b  #1,D0   ; LSR A
    bcs  _L_z00_DriveEffect_ContinueBombSfx
    lsr.b  #1,D0   ; LSR A
    bcs  _L_z00_DriveEffect_ContinueSeaSfx
