_L_z00_DriveEffect_PlaySeaSfx:
    move.b  D3,($0606,A4)
    move.b  #$D0,D0
    move.b  D0,($05F3,A4)
    moveq   #16,D0
    move.b  D0,($0068,A4)
    even
_L_z00_DriveEffect_ContinueSeaSfx:
    move.b  ($05F3,A4),D0
    cmpi.b  #$BF,D0
    bcs  _anon_z00_4
    ; SFX counter >= $BF. Increase volume fast.
    ;
    addq.b  #1,($0068,A4)
    bne  _L_z00_DriveEffect_SetSeaSfxParams
_anon_z00_4:
    ; SFX counter < $BF. Decrease volume slowly down to $10 --
    ; when (counter MOD 8) = 7.
    ;
    move.b  ($05F3,A4),D0
    lsr.b  #1,D0   ; LSR A
    bcc  _L_z00_DriveEffect_SetSeaSfxParams
    lsr.b  #1,D0   ; LSR A
    bcc  _L_z00_DriveEffect_SetSeaSfxParams
    lsr.b  #1,D0   ; LSR A
    bcc  _L_z00_DriveEffect_SetSeaSfxParams
    move.b  ($0068,A4),D0
    cmpi.b  #$10,D0
    beq  _L_z00_DriveEffect_SetSeaSfxParams
    subq.b  #1,($0068,A4)
    even
