    dc.b    $3A, $81, $16, $30, $1A, $82, $34, $00
    dc.b    $94, $56, $42, $02, $4C, $52, $42, $5C
    dc.b    $4A, $5A, $02, $4C, $5A, $56, $02, $50
    dc.b    $4C, $5A, $02, $54, $5A, $58, $02, $50
    dc.b    $54, $4C, $42, $02, $4C, $50, $48, $4A
    dc.b    $50, $00, $8A, $08, $08, $08, $85, $3C
    dc.b    $3A, $38, $36, $3A, $38, $36, $34, $38
    dc.b    $36, $34, $32, $36, $34, $32, $30, $34
    dc.b    $32, $30, $2E, $2A, $28, $A8, $26, $00

    even
DriveTune1:
    move.b  ($0602,A4),D0
