    bne  _L_z00_DriveTune1_ChangeTune
    move.b  ($0607,A4),D0
    bne  _L_z00_DriveTune1_KeepPlaying
    rts

    even
_L_z00_DriveTune1_SilenceThenPlay:
    bsr     SilenceSong
    move.b  #$80,D0
    even
_L_z00_DriveTune1_ChangeTune:
    move.b  D0,($0607,A4)
    moveq   #0,D3
_anon_z00_5:
    ; Get the index for the song bit: 1 to 8.
    ;
    addq.b  #1,D3
    lsr.b  #1,D0   ; LSR A
    bcc  _anon_z00_5
    lea     (TuneScripts1-1).l,A0
    move.b  (A0,D3.W),D0
    move.b  D0,($0618,A4)
    moveq   #1,D0
    move.b  D0,($006F,A4)
    even
_L_z00_DriveTune1_KeepPlaying:
    subq.b  #1,($006F,A4)
    bne  _L_z00_DriveTune1_CheckVibrate
    move.b  ($0618,A4),D3
    addq.b  #1,($0618,A4)
    lea     (TuneScripts1).l,A0
    move.b  (A0,D3.W),D0
    bmi  _L_z00_DriveTune1_PrepNote
    bne  _L_z00_DriveTune1_PlayNote
    ; We've reached the end of the tune.
    ;
    ; If tune is "Game Over", then go play it again.
    ;
    move.b  ($0607,A4),D0
    cmpi.b  #$40,D0
    beq  _L_z00_DriveTune1_ChangeTune
    move.b  #$90,D2
    move.l  D0,-(SP)       ; save A (6502 STX/STY never modifies A)
    move.b  D2,D0  ; D2 → D0 for I/O write
    bsr     _apu_write_4004  ; APU/IO write
    move.l  (SP)+,D0       ; restore A
    moveq   #24,D2
    move.l  D0,-(SP)       ; save A (6502 STX/STY never modifies A)
    move.b  D2,D0  ; D2 → D0 for I/O write
    bsr     _apu_write_4007  ; APU/IO write
    move.l  (SP)+,D0       ; restore A
    moveq   #0,D2
    move.b  D2,($0607,A4)
    move.l  D0,-(SP)       ; save A (6502 STX/STY never modifies A)
    move.b  D2,D0  ; D2 → D0 for I/O write
    bsr     _apu_write_4006  ; APU/IO write
    move.l  (SP)+,D0       ; restore A
    rts

    even
_L_z00_DriveTune1_PrepNote:
    andi.b #$7F,D0
    move.b  D0,($006E,A4)
    move.b  ($0618,A4),D3
    addq.b  #1,($0618,A4)
    lea     (TuneScripts1).l,A0
    move.b  (A0,D3.W),D0
    even
_L_z00_DriveTune1_PlayNote:
    bsr     EmitSquareNote1
    moveq   #127,D0
    bsr     _apu_write_4005  ; APU/IO write
    move.b  #$86,D0
    bsr     _apu_write_4004  ; APU/IO write
    move.b  ($006E,A4),D0
    move.b  D0,($006F,A4)
    moveq   #31,D0
    move.b  D0,($006D,A4)
    even
_L_z00_DriveTune1_CheckVibrate:
    ; If the tune is not one of "flute" or "Link dying", then return.
    ;
    move.b  ($0607,A4),D0
    andi.b #$90,D0
    beq  _L_z00_DriveTune1_Exit
    move.b  ($006D,A4),D3
    beq  _anon_z00_6
    subq.b  #1,($006D,A4)
_anon_z00_6:
    lea     (CustomEnvelopeTune1).l,A0
    move.b  (A0,D3.W),D0
    bsr     _apu_write_4004  ; APU/IO write
    move.b  ($006F,A4),D0
    move.b  ($006B,A4),D2
    bsr     VibratePitch
    move.l  D0,-(SP)       ; save A (6502 STX/STY never modifies A)
    move.b  D2,D0  ; D2 → D0 for I/O write
    bsr     _apu_write_4006  ; APU/IO write
    move.l  (SP)+,D0       ; restore A
    even
_L_z00_DriveTune1_Exit:
    rts

    even
CustomEnvelopeTune1:
    dc.b    $95, $96, $97, $98, $99, $9A, $9B, $9C
