; Params:
; A: note counter
; X: period value
;
; Returns:
; X: (period - 1) to (period + 1)
;
; If note counter < $10, then return.
;
    even
VibratePitch:
    cmpi.b  #$10,D0
    bcs  _L_z00_VibratePitch_Exit
    ; Is bit 2 set?
    ;
    lsr.b  #1,D0   ; LSR A
    lsr.b  #1,D0   ; LSR A
    lsr.b  #1,D0   ; LSR A
    bcs  _L_z00_VibratePitch_GoDown
    ; If not set, then add 1 to X.
    ;
    move.b  D2,D0
    move.b  #$01,D1
    addx.b  D1,D0   ; ADC #$01 (X flag = 6502 C)
    bne  _anon_z00_10
    even
_L_z00_VibratePitch_GoDown:
    ; If set, then subtract 1 from X.
    ;
    move.b  D2,D0
    andi.b  #$EE,CCR  ; CLC: clear C+X
    move.b  #$FF,D1
    addx.b  D1,D0   ; ADC #$FF (X flag = 6502 C)
_anon_z00_10:
    move.b  D0,D2
    even
_L_z00_VibratePitch_Exit:
    rts

    even
KeepPlaying:
    jmp     KeepPlayingSong

    even
DriveSong:
    move.b  ($0600,A4),D0
    bne  _L_z00_DriveSong_ChangeSong
    move.b  ($0609,A4),D0
    bne  KeepPlaying
    rts

    even
_L_z00_DriveSong_ChangeSong:
    move.b  D0,($0609,A4)
    bmi  _L_z00_DriveSong_PlayFirstDemoPhrase
    cmpi.b  #$06,D0
    bne  _anon_z00_11
    moveq   #36,D3
    bne  PrepPhrase
_anon_z00_11:
    cmpi.b  #$01,D0
    beq  _L_z00_DriveSong_PlayFirstOverworldPhrase
    cmpi.b  #$40,D0
    beq  _L_z00_DriveSong_PlayFirstUnderworldPhrase
    cmpi.b  #$10,D0
    bne  PlayNextPhrase
    moveq   #17,D3
    bne  SetPrevPhraseIndex
    even
_L_z00_DriveSong_PlayFirstDemoPhrase:
    moveq   #25,D3
    bne  SetPrevPhraseIndex
    even
_L_z00_DriveSong_PlayFirstUnderworldPhrase:
    moveq   #15,D3
    bne  SetPrevPhraseIndex
    even
_L_z00_DriveSong_PlayFirstOverworldPhrase:
    moveq   #8,D3
    even
SetPrevPhraseIndex:
    move.b  D3,($006C,A4)
    even
PlayNextPhrase:
    move.b  D0,D2
    bmi  _L_z00_PlayNextPhrase_PlayNextDemoPhrase
    cmpi.b  #$01,D0
    beq  _L_z00_PlayNextPhrase_PlayNextOverworldPhrase
    cmpi.b  #$40,D0
    beq  _L_z00_PlayNextPhrase_PlayNextUnderworldPhrase
    cmpi.b  #$10,D0
    bne  _L_z00_PlayNextPhrase_PlaySinglePhraseSong
    ; Play the next phrase of the ending song.
    ;
    addq.b  #1,($006C,A4)
    move.b  ($006C,A4),D3
    cmpi.b  #$1A,D3
    bne  PrepPhrase
    moveq   #20,D3
    bne  SetPrevPhraseIndex
    even
_L_z00_PlayNextPhrase_PlayNextUnderworldPhrase:
    addq.b  #1,($006C,A4)
    move.b  ($006C,A4),D3
    cmpi.b  #$12,D3
    bne  PrepPhrase
    moveq   #15,D3
    bne  SetPrevPhraseIndex
    even
_L_z00_PlayNextPhrase_PlayNextOverworldPhrase:
    addq.b  #1,($006C,A4)
    move.b  ($006C,A4),D3
    cmpi.b  #$10,D3
    bne  PrepPhrase
    moveq   #9,D3
    bne  SetPrevPhraseIndex
    even
_L_z00_PlayNextPhrase_PlayNextDemoPhrase:
    addq.b  #1,($006C,A4)
    move.b  ($006C,A4),D3
    cmpi.b  #$24,D3
    bne  PrepPhrase
    moveq   #25,D3
    bne  SetPrevPhraseIndex
    even
_L_z00_PlayNextPhrase_PlaySinglePhraseSong:
    ; Get the index for the song bit: 2 to 6.
    ;
    move.b  D2,D0
    moveq   #0,D3
_anon_z00_12:
    addq.b  #1,D3
    lsr.b  #1,D0   ; LSR A
    bcc  _anon_z00_12
    even
PrepPhrase:
    lea     (SongTable-1).l,A0
    move.b  (A0,D3.W),D0
    move.b  D0,D3
    lea     (SongTable).l,A0
    move.b  (A0,D3.W),D0
    move.b  D0,($05F4,A4)
    lea     (SongTable+1).l,A0
    move.b  (A0,D3.W),D0
    move.b  D0,($0066,A4)
    lea     (SongTable+2).l,A0
    move.b  (A0,D3.W),D0
    move.b  D0,($0067,A4)
    lea     (SongTable+3).l,A0
    move.b  (A0,D3.W),D0
    move.b  D0,($060C,A4)
    lea     (SongTable+4).l,A0
    move.b  (A0,D3.W),D0
    move.b  D0,($060B,A4)
    lea     (SongTable+5).l,A0
    move.b  (A0,D3.W),D0
    move.b  D0,($060D,A4)
    move.b  D0,($05F5,A4)
    lea     (SongTable+6).l,A0
    move.b  (A0,D3.W),D0
    move.b  D0,($0619,A4)
    lea     (SongTable+7).l,A0
    move.b  (A0,D3.W),D0
    move.b  D0,($05F1,A4)
    moveq   #1,D0
    move.b  D0,($0611,A4)
    move.b  D0,($0613,A4)
    move.b  D0,($0616,A4)
    move.b  D0,($0617,A4)
    lsr.b  #1,D0   ; LSR A
    move.b  D0,($060A,A4)
    even
KeepPlayingSong:
    subq.b  #1,($0611,A4)
    bne  ApplySq1Effects
    move.b  ($060A,A4),D3
    addq.b  #1,($060A,A4)
    move.b  ($66,A4),D1   ; ptr lo
    move.b  ($67,A4),D4  ; ptr hi
    lsl.w   #8,D4
    or.w    D1,D4             ; D4 = NES ptr addr
    ext.l   D4
    add.l   #NES_RAM,D4       ; → Genesis addr
    movea.l D4,A0
    move.b  (A0,D3.W),D0     ; LDA ($nn),Y
    beq  _L_z00_KeepPlayingSong_SongEnded
    bpl  PlayNote
    bne  PrepNote
    even
_L_z00_KeepPlayingSong_SongEnded:
    ; If this is a song that repeats, then go play again.
    ;
    move.b  ($0609,A4),D0
    andi.b #$F1,D0
    bne  PlayAgain
    even
SilenceSong:
    moveq   #0,D0
    move.b  D0,($0609,A4)
    bsr     _apu_write_4015  ; APU/IO write
    moveq   #15,D0
    bsr     _apu_write_4015  ; APU/IO write
    rts

    even
PlayAgain:
    jmp     PlayNextPhrase

    even
PrepNote:
    bsr     GetSongNoteLength
    move.b  D0,($0610,A4)
    move.b  ($060A,A4),D3
    addq.b  #1,($060A,A4)
    move.b  ($66,A4),D1   ; ptr lo
    move.b  ($67,A4),D4  ; ptr hi
    lsl.w   #8,D4
    or.w    D1,D4             ; D4 = NES ptr addr
    ext.l   D4
    add.l   #NES_RAM,D4       ; → Genesis addr
    movea.l D4,A0
    move.b  (A0,D3.W),D0     ; LDA ($nn),Y
    even
PlayNote:
    ; If something is playing in tune channel 1, then
    ; don't play a square note here.
    ;
    move.b  ($0607,A4),D2
    bne  _L_z00_PlayNote_SkipSq1
    bsr     EmitSquareNote1
    beq  _anon_z00_13
    bsr     PrepareCustomSongEnvelope
_anon_z00_13:
    move.b  D0,($0612,A4)
    bsr     SetSq1DutyAndSweep
    moveq   #0,D0
    move.b  D0,($061B,A4)
    even
_L_z00_PlayNote_SkipSq1:
    move.b  ($0610,A4),D0
    move.b  D0,($0611,A4)
    even
ApplySq1Effects:
    ; If something is playing in tune channel 1, then
    ; skip effects for square channel 1.
    ;
    move.b  ($0607,A4),D3
    bne  _L_z00_ApplySq1Effects_HandleSq0
    addq.b  #1,($061B,A4)
    move.b  ($0612,A4),D3
    beq  _anon_z00_14
    subq.b  #1,($0612,A4)
_anon_z00_14:
    bsr     ShapeSongVolume
    bsr     _apu_write_4004  ; APU/IO write
    moveq   #127,D2
    move.l  D0,-(SP)       ; save A (6502 STX/STY never modifies A)
    move.b  D2,D0  ; D2 → D0 for I/O write
    bsr     _apu_write_4005  ; APU/IO write
    move.l  (SP)+,D0       ; restore A
    move.b  ($0609,A4),D0
    bpl  _L_z00_ApplySq1Effects_HandleSq0
