    ;
    move.b  ($061B,A4),D0
    move.b  ($006B,A4),D2
    bsr     VibratePitch
    move.l  D0,-(SP)       ; save A (6502 STX/STY never modifies A)
    move.b  D2,D0  ; D2 → D0 for I/O write
    bsr     _apu_write_4006  ; APU/IO write
    move.l  (SP)+,D0       ; restore A
    even
_L_z00_ApplySq1Effects_HandleSq0:
    move.b  ($060B,A4),D3
    beq  _L_z00_ApplySq1Effects_HandleTrg
    subq.b  #1,($0613,A4)
    bne  _L_z00_ApplySq1Effects_ApplySq0Effects
    move.b  ($060B,A4),D3
    addq.b  #1,($060B,A4)
    move.b  ($66,A4),D1   ; ptr lo
    move.b  ($67,A4),D4  ; ptr hi
    lsl.w   #8,D4
    or.w    D1,D4             ; D4 = NES ptr addr
    ext.l   D4
    add.l   #NES_RAM,D4       ; → Genesis addr
    movea.l D4,A0
    move.b  (A0,D3.W),D0     ; LDA ($nn),Y
    bpl  _L_z00_ApplySq1Effects_PlaySq0
    bsr     GetSongNoteLength
    move.b  D0,($060F,A4)
    move.b  ($060B,A4),D3
    addq.b  #1,($060B,A4)
    move.b  ($66,A4),D1   ; ptr lo
    move.b  ($67,A4),D4  ; ptr hi
    lsl.w   #8,D4
    or.w    D1,D4             ; D4 = NES ptr addr
    ext.l   D4
    add.l   #NES_RAM,D4       ; → Genesis addr
    movea.l D4,A0
    move.b  (A0,D3.W),D0     ; LDA ($nn),Y
    even
_L_z00_ApplySq1Effects_PlaySq0:
    move.b  ($0605,A4),D2
    bne  _L_z00_ApplySq1Effects_SkipSq0
    bsr     EmitSquareNote0
    beq  _anon_z00_15
    bsr     PrepareCustomSongEnvelope
_anon_z00_15:
    move.b  D0,($0614,A4)
    bsr     SetSq0DutyAndSweep
    moveq   #0,D0
    move.b  D0,($061C,A4)
    even
_L_z00_ApplySq1Effects_SkipSq0:
    move.b  ($060F,A4),D0
    move.b  D0,($0613,A4)
    even
_L_z00_ApplySq1Effects_ApplySq0Effects:
    move.b  ($0605,A4),D2
    bne  _L_z00_ApplySq1Effects_HandleTrg
    addq.b  #1,($061C,A4)
    move.b  ($0614,A4),D3
    beq  _anon_z00_16
    subq.b  #1,($0614,A4)
_anon_z00_16:
    bsr     ShapeSongVolume
    bsr     _apu_write_4000  ; APU/IO write
    move.b  ($0609,A4),D0
    bpl  _anon_z00_17
    ; The demo/title song ($80) vibrates the pitch.
    ;
    move.b  ($061C,A4),D0
    move.b  ($006A,A4),D2
    bsr     VibratePitch
    move.l  D0,-(SP)       ; save A (6502 STX/STY never modifies A)
    move.b  D2,D0  ; D2 → D0 for I/O write
    bsr     _apu_write_4002  ; APU/IO write
    move.l  (SP)+,D0       ; restore A
_anon_z00_17:
    moveq   #127,D0
    bsr     _apu_write_4001  ; APU/IO write
    even
_L_z00_ApplySq1Effects_HandleTrg:
    move.b  ($060C,A4),D0
    bne  _anon_z00_18
    jmp     _L_z00_ApplySq1Effects_HandleNoise

_anon_z00_18:
    subq.b  #1,($0616,A4)
    bne  _L_z00_ApplySq1Effects_ApplyTrgEffects
    even
_L_z00_ApplySq1Effects_PrepNoteOrPassage:
    move.b  ($060C,A4),D3
    addq.b  #1,($060C,A4)
    move.b  ($66,A4),D1   ; ptr lo
    move.b  ($67,A4),D4  ; ptr hi
    lsl.w   #8,D4
    or.w    D1,D4             ; D4 = NES ptr addr
    ext.l   D4
    add.l   #NES_RAM,D4       ; → Genesis addr
    movea.l D4,A0
    move.b  (A0,D3.W),D0     ; LDA ($nn),Y
    beq  _L_z00_ApplySq1Effects_SetTrgLinear
    bpl  _L_z00_ApplySq1Effects_PlayNoteTrg
    cmpi.b  #$F0,D0
    beq  _L_z00_ApplySq1Effects_EndOfPassage
    bcc  _L_z00_ApplySq1Effects_PrepNoteTrg
    ; Control note >= $F1. The low nibble defines the number of
    ; repetititions of the passage starting at the next offset.
    ;
    ori.b   #$11,CCR  ; SEC: set C+X
    move.b  #$F0,D1
    subx.b  D1,D0   ; SBC #$F0
    move.b  D0,($061E,A4)
    move.b  ($060C,A4),D0
    move.b  D0,($061F,A4)
    jmp     _L_z00_ApplySq1Effects_PrepNoteOrPassage

    even
_L_z00_ApplySq1Effects_EndOfPassage:
    subq.b  #1,($061E,A4)
    beq  _anon_z00_19
    move.b  ($061F,A4),D0
    move.b  D0,($060C,A4)
_anon_z00_19:
    jmp     _L_z00_ApplySq1Effects_PrepNoteOrPassage

    even
_L_z00_ApplySq1Effects_PrepNoteTrg:
    bsr     GetSongNoteLength
    move.b  D0,($0615,A4)
    moveq   #31,D0
    bsr     _apu_write_4008  ; APU/IO write
    move.b  ($060C,A4),D3
    addq.b  #1,($060C,A4)
    move.b  ($66,A4),D1   ; ptr lo
    move.b  ($67,A4),D4  ; ptr hi
    lsl.w   #8,D4
    or.w    D1,D4             ; D4 = NES ptr addr
    ext.l   D4
    add.l   #NES_RAM,D4       ; → Genesis addr
    movea.l D4,A0
    move.b  (A0,D3.W),D0     ; LDA ($nn),Y
    beq  _L_z00_ApplySq1Effects_SetTrgLinear
    even
_L_z00_ApplySq1Effects_PlayNoteTrg:
    bsr     EmitTriangleNote
    moveq   #0,D0
    move.b  D0,($061D,A4)
    move.b  ($0615,A4),D2
    move.b  D2,($0616,A4)
    even
_L_z00_ApplySq1Effects_ApplyTrgEffects:
    addq.b  #1,($061D,A4)
    move.b  ($061D,A4),D0
    move.b  ($05F0,A4),D2
    bsr     VibratePitch
    move.l  D0,-(SP)       ; save A (6502 STX/STY never modifies A)
    move.b  D2,D0  ; D2 → D0 for I/O write
    bsr     _apu_write_400a  ; APU/IO write
    move.l  (SP)+,D0       ; restore A
    ; TODO: [05F1] ?
    ;
    move.b  ($05F1,A4),D0
    bpl  _anon_z00_20
    moveq   #31,D0
    bne  _L_z00_ApplySq1Effects_SetTrgLinear
_anon_z00_20:
    move.b  #$FF,D0
    even
_L_z00_ApplySq1Effects_SetTrgLinear:
    bsr     _apu_write_4008  ; APU/IO write
    even
_L_z00_ApplySq1Effects_HandleNoise:
    ; If the song is not demo nor ending, then return.
    ; They don't use noise.
    ;
    move.b  ($0609,A4),D0
    andi.b #$91,D0
    beq  _L_z00_ApplySq1Effects_Exit
    subq.b  #1,($0617,A4)
    bne  _L_z00_ApplySq1Effects_Exit
_anon_z00_21:
    move.b  ($060D,A4),D3
    addq.b  #1,($060D,A4)
    move.b  ($66,A4),D1   ; ptr lo
    move.b  ($67,A4),D4  ; ptr hi
    lsl.w   #8,D4
    or.w    D1,D4             ; D4 = NES ptr addr
    ext.l   D4
    add.l   #NES_RAM,D4       ; → Genesis addr
    movea.l D4,A0
    move.b  (A0,D3.W),D0     ; LDA ($nn),Y
    bne  _anon_z00_22
    ; We've reached the end of the track. Noise always repeats.
    ;
    move.b  ($05F5,A4),D0
    move.b  D0,($060D,A4)
    bne  _anon_z00_21
_anon_z00_22:
    bsr     GetSongNoiseNoteLength
    move.b  D0,($0617,A4)
    ; From the original control note, extract an index 0-3
    ; to look up noise parameters.
    ;
    move.b  D2,D0
    andi.b #$3E,D0
    lsr.b  #1,D0   ; LSR A
    lsr.b  #1,D0   ; LSR A
    lsr.b  #1,D0   ; LSR A
    lsr.b  #1,D0   ; LSR A
    move.b  D0,D3
    lea     (NoiseVolumes).l,A0
    move.b  (A0,D3.W),D0
    bsr     _apu_write_400c  ; APU/IO write
    lea     (NoisePeriods).l,A0
    move.b  (A0,D3.W),D0
    bsr     _apu_write_400e  ; APU/IO write
    lea     (NoiseLengths).l,A0
    move.b  (A0,D3.W),D0
    bsr     _apu_write_400f  ; APU/IO write
    even
_L_z00_ApplySq1Effects_Exit:
    rts

    even
NoiseVolumes:
    dc.b    $10, $1C, $1C, $1C

    even
NoisePeriods:
    dc.b    $00, $03, $0A, $03

    even
NoiseLengths:
    dc.b    $00, $18, $18, $58

; Params:
; A: control note
;
; Returns:
; A: note length
; X: original control note
;
; Rotate so that bits 0, 7, 6 move to bits 2, 1, 0.
;
    even
GetSongNoiseNoteLength:
    move.b  D0,D2
    roxr.b  #1,D0   ; ROR A
    move.b  D2,D0
    roxl.b  #1,D0   ; ROL A
    roxl.b  #1,D0   ; ROL A
    roxl.b  #1,D0   ; ROL A
; Params:
; A: control note
;
; Returns:
; A: note length
;
    even
GetSongNoteLength:
    andi.b #$07,D0
    andi.b  #$EE,CCR  ; CLC: clear C+X
    move.b  ($05F4,A4),D1
    addx.b  D1,D0   ; ADC NoteLengthTableBase
    move.b  D0,D3
    lea     (NoteLengthTable0).l,A0
    move.b  (A0,D3.W),D0
    rts

    even
GetSongNoteLengthWithAbsIndex:
    andi.b #$07,D0
    move.b  D0,D3
    lea     (NoteLengthTable0).l,A0
    move.b  (A0,D3.W),D0
    rts

; Unknown block
    dc.b    $CB

    even
StairsSfxNotes:
    dc.b    $0E, $0E, $4C, $6D, $8C, $CD

; Unknown block
    dc.b    $FF

; Big-endian 16-bit period values.
;
    even
NotePeriodTable:
    dc.b    $00, $23, $00, $6A, $03, $27, $00, $97
    dc.b    $00, $00, $02, $F9, $02, $CF, $02, $A6
    dc.b    $02, $80, $02, $5C, $02, $3A, $02, $1A
    dc.b    $01, $FC, $01, $DF, $01, $C4, $01, $AB
    dc.b    $01, $93, $01, $7C, $01, $67, $01, $53
    dc.b    $01, $40, $01, $2E, $01, $1D, $01, $0D
    dc.b    $00, $FE, $00, $EF, $00, $E2, $00, $D5
    dc.b    $00, $C9, $00, $BE, $00, $B3, $00, $A9
    dc.b    $00, $A0, $00, $8E, $00, $86, $00, $77
    dc.b    $00, $7E, $00, $71, $00, $54, $00, $64
    dc.b    $00, $5F, $00, $59, $00, $50, $00, $47
    dc.b    $00, $43, $00, $3F, $00, $38, $00, $32
    dc.b    $00, $21, $05, $4D, $05, $01, $04, $B9
    dc.b    $04, $35, $03, $F8, $03, $BF, $03, $89
    dc.b    $03, $57

; Returns:
; A: starting custom envelope offset
; X: duty byte $82
; Y: sweep byte $7F
;
    even
PrepareCustomSongEnvelope:
    move.b  ($0619,A4),D0
    moveq   #32,D0
    move.b  #$82,D2
    moveq   #127,D3
    rts

; Params:
; Y: envelope offset
;
; Returns:
; A: duty/volume value
;
    even
ShapeSongVolume:
    move.b  ($0619,A4),D0
    bpl  _anon_z00_23
    lea     (CustomEnvelopeSong).l,A0
    move.b  (A0,D3.W),D0
    andi.b #$0F,D0
    bne  _L_z00_ShapeSongVolume_ReturnValue
_anon_z00_23:
    lea     (CustomEnvelopeSong).l,A0
    move.b  (A0,D3.W),D0
    lsr.b  #1,D0   ; LSR A
    lsr.b  #1,D0   ; LSR A
    lsr.b  #1,D0   ; LSR A
    lsr.b  #1,D0   ; LSR A
    even
_L_z00_ShapeSongVolume_ReturnValue:
    ori.b #$90,D0
    rts

    even
CustomEnvelopeSong:
    dc.b    $04, $24, $24, $34, $34, $35, $35, $35
    dc.b    $45, $45, $46, $46, $46, $46, $46, $46
    dc.b    $46, $46, $57, $57, $57, $57, $68, $68
    dc.b    $68, $68, $79, $79, $79, $68, $68, $57

    even
SwordSfxNotes:
    dc.b    $47, $67, $87, $A8, $B9, $9A, $8A, $5A
    dc.b    $9B, $8B

    even
ArrowSfxNotes:
    dc.b    $FB, $F9, $9D, $6E, $3F

    even
FlameSfxNotes:
    dc.b    $1A, $1A, $1C, $1D, $1D, $1E, $1E, $1F
    dc.b    $1F, $1E, $1A, $19, $16, $13, $11, $11

    even
NoteLengthTable0:
    dc.b    $03, $0A, $01, $14, $05, $28, $3C, $70

    even
NoteLengthTable1:
    dc.b    $07, $1B, $35, $14, $0D, $28, $3C, $50

    even
NoteLengthTable2:
    dc.b    $06, $0C, $08, $18, $24, $30, $48, $10

    even
NoteLengthTable3:
